parameters.jsCode:
// Estrae e valida l'output dell'LLM, gestendo entrambe le shape
// (Ollama vs OpenAI). Tre comportamenti chiave:
//
// 1. Disambiguazione provider: la presenza di `response.choices` indica
//    OpenAI; la presenza di `response.response` indica Ollama. Si fallback
//    a varie altre shape conosciute per robustezza.
// 2. Parse difensivo: se l'LLM restituisce qualcosa di non parsabile, la
//    richiesta viene comunque processata con un fallback conservativo
//    (urgenza 'alta', solo ticket) anziche fallire l'esecuzione.
// 3. Sanitizzazione: clamp dei valori enum su quelli ammessi,
//    normalizzazione delle azioni in array non vuoto.

const input = $input.first().json;

// Riconoscimento provider e estrazione del testo grezzo
let raw = null;
let provider_usato = 'sconosciuto';
let usage_info = null;
let latenza_ms = null;

if (input.choices && Array.isArray(input.choices) && input.choices.length > 0) {
  // Shape OpenAI Chat Completions
  raw = input.choices[0]?.message?.content;
  provider_usato = 'openai';
  usage_info = input.usage || null;
} else if (typeof input.response === 'string') {
  // Shape Ollama /api/generate
  raw = input.response;
  provider_usato = 'ollama';
  if (input.total_duration) {
    latenza_ms = Math.round(input.total_duration / 1e6);
  }
} else if (input.body?.response) {
  raw = input.body.response;
  provider_usato = 'ollama';
} else if (input.message?.content) {
  raw = input.message.content;
  provider_usato = 'ollama-chat';
} else {
  raw = input.data?.response || input.data?.choices?.[0]?.message?.content || null;
}

let interpretazione;
let parse_ok = true;
let parse_error = null;

try {
  if (raw == null) throw new Error('output LLM vuoto o shape non riconosciuta');
  interpretazione = typeof raw === 'string' ? JSON.parse(raw) : raw;
  if (!interpretazione || typeof interpretazione !== 'object') {
    throw new Error('output non è un oggetto JSON');
  }
} catch (err) {
  parse_ok = false;
  parse_error = err.message;
  interpretazione = {
    intento: 'altro',
    cliente: { nome: null, id_cliente: null },
    servizio: null,
    urgenza: 'alta',
    azioni_richieste: ['ticket'],
    sentiment: 'neutro',
    motivazione_urgenza: 'fallback: parsing LLM fallito, escalation a revisione manuale',
    contesto: 'Richiesta da interpretare manualmente.'
  };
}

// Validazione difensiva sui campi critici
const urgenze_ammesse = ['bassa', 'media', 'alta', 'critica'];
if (!urgenze_ammesse.includes(interpretazione.urgenza)) {
  interpretazione.urgenza = 'media';
}
if (!Array.isArray(interpretazione.azioni_richieste) || interpretazione.azioni_richieste.length === 0) {
  interpretazione.azioni_richieste = ['ticket'];
}

// Recupero dati di contesto dalla richiesta originale e dal config provider
const contesto_richiesta = $('Normalizza Input').first().json;
const config = $('Configura Provider LLM').first().json;

return [{
  json: {
    correlation_id: contesto_richiesta.correlation_id,
    canale: contesto_richiesta.canale,
    mittente: contesto_richiesta.mittente,
    testo_originale: contesto_richiesta.testo,
    ricevuta_at: contesto_richiesta.ricevuta_at,
    interpretazione,
    interpretazione_meta: {
      parse_ok,
      parse_error,
      provider_richiesto: config.provider,
      provider_usato,
      modello: config.modello_llm,
      latenza_ms,
      tokens: usage_info
    }
  }
}];

// Agente decisionale deterministico.
// Trasforma l'interpretazione semantica in un piano operativo composto da
// azioni discrete, ognuna con parametri, priorità e flag di approvazione.
//
// Lo scoring di priorità combina:
//   - urgenza:     bassa=10, media=30, alta=60, critica=90
//   - sentiment:   frustrato/preoccupato +10, soddisfatto -5
//   - servizio:    campagna_pubblicitaria +5, supporto_tecnico +10
// Il punteggio finale guida l'ordinamento delle azioni se eseguite
// sequenzialmente; in modalita parallela serve come metadato per i log.
//
// L'approvazione umana scatta quando ALMENO una delle condizioni è vera:
//   - urgenza == 'critica'
//   - intento in {escalation, aggiornamento_crm} su clienti chiave
//   - notifica_marketing su clienti enterprise (rischio reputazionale)
// La definizione di 'cliente chiave' è qui hardcoded a una whitelist;
// in produzione sarebbe una lookup contro il CRM.

const dati = $input.first().json;
const interp = dati.interpretazione;

const PUNTI_URGENZA = { bassa: 10, media: 30, alta: 60, critica: 90 };
const SENTIMENT_DELTA = { frustrato: 10, preoccupato: 10, soddisfatto: -5, neutro: 0 };
const SERVIZIO_DELTA = {
  campagna_pubblicitaria: 5,
  supporto_tecnico: 10,
  integrazione_sistemi: 5,
  formazione: 0,
  altro: 0
};

const CLIENTI_CHIAVE = ['ACME', 'EnerNova', 'BancaItalsud', 'Pharmacare'];

const punteggio = (PUNTI_URGENZA[interp.urgenza] || 30)
  + (SENTIMENT_DELTA[interp.sentiment] || 0)
  + (SERVIZIO_DELTA[interp.servizio] || 0);

const nome_cliente = interp.cliente?.nome || '';
const e_cliente_chiave = CLIENTI_CHIAVE.some(c => nome_cliente.toUpperCase().includes(c.toUpperCase()));

const azioni_sensibili = ['notifica_marketing'];
const tocca_sensibile = interp.azioni_richieste.some(a => azioni_sensibili.includes(a));

const richiede_approvazione = (
  interp.urgenza === 'critica'
  || interp.intento === 'escalation'
  || (e_cliente_chiave && tocca_sensibile)
);

// Costruzione del piano: una entry per azione, con parametri tipizzati.
const piano = [];

for (const azione of interp.azioni_richieste) {
  switch (azione) {
    case 'analisi':
      piano.push({
        tipo: 'analisi',
        target: 'team_data',
        params: { servizio: interp.servizio, contesto: interp.contesto },
        priorità: punteggio
      });
      break;
    case 'ticket':
      piano.push({
        tipo: 'ticket',
        target: 'sistema_ticketing',
        params: {
          titolo: `${interp.intento.replace(/_/g, ' ')} - ${nome_cliente || 'cliente non specificato'}`,
          descrizione: dati.testo_originale,
          cliente: interp.cliente,
          servizio: interp.servizio,
          urgenza: interp.urgenza,
          motivazione: interp.motivazione_urgenza
        },
        priorità: punteggio
      });
      break;
    case 'aggiornamento_crm':
      piano.push({
        tipo: 'crm',
        target: 'crm_clienti',
        params: {
          cliente: interp.cliente,
          evento: interp.intento,
          note: interp.contesto,
          canale_origine: dati.canale
        },
        priorità: punteggio
      });
      break;
    case 'notifica_marketing':
      piano.push({
        tipo: 'notifica',
        target: 'team_marketing',
        params: {
          cliente: interp.cliente,
          oggetto: `[${interp.urgenza.toUpperCase()}] Anomalia segnalata - ${nome_cliente}`,
          messaggio: interp.contesto
        },
        priorità: punteggio
      });
      break;
    case 'notifica_tecnico':
      piano.push({
        tipo: 'notifica',
        target: 'team_tecnico',
        params: {
          cliente: interp.cliente,
          oggetto: `[${interp.urgenza.toUpperCase()}] Intervento tecnico richiesto`,
          messaggio: interp.contesto
        },
        priorità: punteggio
      });
      break;
    case 'report':
      piano.push({
        tipo: 'report',
        target: 'reportistica',
        params: { cliente: interp.cliente, servizio: interp.servizio },
        priorità: punteggio
      });
      break;
    default:
      // Azioni non riconosciute confluiscono in un ticket generico
      piano.push({
        tipo: 'ticket',
        target: 'sistema_ticketing',
        params: {
          titolo: 'Richiesta non classificata',
          descrizione: dati.testo_originale,
          urgenza: 'media'
        },
        priorità: 30
      });
  }
}

// Ordinamento per priorità decrescente: utile per la presentazione e per
// l'esecuzione sequenziale fallback se una branch parallela non è disponibile.
piano.sort((a, b) => b.priorità - a.priorità);

return [{
  json: {
    ...dati,
    decisione: {
      piano,
      richiede_approvazione,
      punteggio_priorità: punteggio,
      cliente_chiave: e_cliente_chiave,
      generato_at: new Date().toISOString()
    }
  }
}];

parameters.message:
=Una richiesta interna proveniente dal canale '{{ $json.canale }}' richiede approvazione prima dell'esecuzione automatica.

Mittente: {{ $json.mittente.nome }} ({{ $json.mittente.email }})
Urgenza: {{ $json.interpretazione.urgenza.toUpperCase() }}
Motivazione: {{ $json.interpretazione.motivazione_urgenza }}
Punteggio priorità: {{ $json.decisione.punteggio_priorità }}/100
Cliente chiave: {{ $json.decisione.cliente_chiave ? 'si' : 'no' }}
Provider LLM usato: {{ $json.interpretazione_meta.provider_usato }} ({{ $json.interpretazione_meta.modello }})

Testo della richiesta:
>>> {{ $json.testo_originale }} <<<

Piano operativo proposto ({{ $json.decisione.piano.length }} azioni):
{{ $json.decisione.piano.map((a, i) => (i+1) + '. ' + a.tipo.toUpperCase() + ' → ' + a.target + ' (priorità ' + a.priorità + ')').join('\n') }}

ID correlazione: {{ $json.correlation_id }}

parameters.jsCode:
// Cattura l'esito dell'approvazione e arricchisce il payload.
// L'output del nodo Send-and-Wait varia leggermente per versione di n8n: in
// genere espone $json.approved (boolean) o $json.data.approved. Gestiamo
// entrambi i pattern.

const dati_orig = $('Agente Decisionale').first().json;
const risposta = $input.first().json;
const approvato = risposta.approved ?? risposta.data?.approved ?? false;

return [{
  json: {
    ...dati_orig,
    approvazione: {
      richiesta: true,
      esito: approvato ? 'approvata' : 'rifiutata',
      timestamp: new Date().toISOString(),
      approvatore: 'operations@digitserve.it'
    }
  }
}];

// Esegui - Crea Ticket  (simulazione interna)
//
// Workflow autocontenuto: il nodo simula la creazione di un ticket nel sistema
// aziendale e produce direttamente l'`esito_azione` nel formato uniforme atteso
// dai nodi a valle.
//
// PASSAGGIO A PRODUZIONE: sostituire questo Code con un nodo HTTP Request
// configurato sull'endpoint reale (Jira REST API v3, ServiceNow Table API, ecc.).
// Lo schema dell'output non cambia: solo il body di chiamata.

const azione = $json.azione_corrente;
const ticket_id = 'TKT-' +
  Date.now().toString(36).toUpperCase().slice(-6) + '-' +
  Math.random().toString(36).slice(2, 6).toUpperCase();

return [{
  json: {
    ...$json,
    esito_azione: {
      tipo: 'ticket',
      target: azione.target,
      stato: 'eseguita',
      riferimento: ticket_id,
      errore: null,
      timestamp: new Date().toISOString(),
      dettaglio_mock: {
        titolo: azione.params.titolo,
        cliente: azione.params.cliente,
        urgenza: azione.params.urgenza,
        priorità: azione.priorità
      }
    }
  }
}];

// Esegui - Aggiorna CRM  (simulazione interna)
//
// Simula l'aggiunta di un evento allo storico cliente (Salesforce Activity,
// HubSpot Engagement, schema equivalente in CRM proprietari).
//
// PASSAGGIO A PRODUZIONE: sostituire con HTTP Request, es.:
//   PATCH /api/crm/clienti/{id}/storico  body: { evento, note, canale_origine }
//   risposta:                             { id, evento_id, aggiornato_at }

const azione = $json.azione_corrente;
const id_cliente = (azione.params.cliente && azione.params.cliente.id_cliente) || 'unknown';
const evento_id = 'EVT-' +
  Date.now().toString(36).toUpperCase().slice(-6) + '-' +
  Math.random().toString(36).slice(2, 6).toUpperCase();

return [{
  json: {
    ...$json,
    esito_azione: {
      tipo: 'crm',
      target: azione.target,
      stato: 'eseguita',
      riferimento: evento_id,
      errore: null,
      timestamp: new Date().toISOString(),
      dettaglio_mock: {
        id_cliente,
        evento: azione.params.evento,
        canale_origine: azione.params.canale_origine
      }
    }
  }
}];

// Esegui - Notifica Team  (simulazione interna)
//
// Simula la consegna di una notifica al team interno (marketing o tecnico).
//
// PASSAGGIO A PRODUZIONE: sostituire con un nodo Slack, Microsoft Teams,
// SendGrid, o un HTTP Request verso il sistema di notifiche scelto.

const azione = $json.azione_corrente;
const notifica_id = 'NTF-' +
  Date.now().toString(36).toUpperCase().slice(-6) + '-' +
  Math.random().toString(36).slice(2, 6).toUpperCase();

return [{
  json: {
    ...$json,
    esito_azione: {
      tipo: 'notifica',
      target: azione.target,
      stato: 'eseguita',
      riferimento: notifica_id,
      errore: null,
      timestamp: new Date().toISOString(),
      dettaglio_mock: {
        destinatario: azione.target,
        oggetto: azione.params.oggetto
      }
    }
  }
}];

// Esegui - Programma Report  (simulazione interna)
//
// Simula l'accodamento di un job di reportistica asincrono.
//
// PASSAGGIO A PRODUZIONE: sostituire con HTTP Request verso il sistema di
// reportistica aziendale; tipicamente la chiamata e accept-and-defer (HTTP 202)
// e il report viene completato fuori banda.

const azione = $json.azione_corrente;
const report_id = 'RPT-' +
  Date.now().toString(36).toUpperCase().slice(-6) + '-' +
  Math.random().toString(36).slice(2, 6).toUpperCase();

return [{
  json: {
    ...$json,
    esito_azione: {
      tipo: 'report',
      target: azione.target,
      stato: 'eseguita',
      riferimento: report_id,
      errore: null,
      timestamp: new Date().toISOString(),
      dettaglio_mock: {
        cliente: azione.params.cliente,
        servizio: azione.params.servizio,
        eta_completamento_h: 24
      }
    }
  }
}];

// Ramo 'analisi': non è un'azione esterna ma un task interno per il team data.
// Lo modelliamo come ticket interno con tag 'analisi-preliminare' invece di
// esporre un endpoint dedicato: riduce la superficie di integrazione.

const azione = $json.azione_corrente;
return [{
  json: {
    ...$json,
    esito_azione: {
      tipo: 'analisi',
      stato: 'accodata',
      coda: 'team_data',
      params: azione.params,
      timestamp: new Date().toISOString()
    }
  }
}];

// Pass-through dei branch esecutivi.
// Ogni branch a monte (Crea Ticket, Aggiorna CRM, Notifica Team, Programma
// Report, Accoda Analisi) produce direttamente un `esito_azione` uniforme.
// Questo nodo resta come punto di convergenza e hook per future estensioni:
//   - arricchimento con metadati di rate-limiting,
//   - injection di trace_id per distributed tracing,
//   - validazione dello schema dell'esito prima dell'aggregazione.

return $input.all();

// Costruzione del riepilogo strutturato e dell'audit record.
// Output:
//   - audit_record: snapshot completo destinato all'archivio immutabile.
//   - risposta_sincrona: oggetto restituito al chiamante (subset utile).
//
// Aggreghiamo gli esiti dalle iterazioni precedenti. Il merge di n8n consegna
// un singolo item con array dei dati ricevuti dai branch upstream.

const items = $input.all();
const esiti = items
  .map(it => it.json.esito_azione)
  .filter(Boolean);

const dati_base = items[0]?.json || {};

const totali = {
  totali: esiti.length,
  eseguite: esiti.filter(e => e.stato === 'eseguita').length,
  fallite: esiti.filter(e => e.stato === 'fallita').length,
  accodate: esiti.filter(e => e.stato === 'accodata').length,
  sconosciute: esiti.filter(e => e.stato === 'sconosciuto').length
};

const esito_complessivo = (
  totali.fallite > 0 ? 'parziale' :
  totali.totali === 0 ? 'nessuna_azione' :
  'completata'
);

const audit_record = {
  correlation_id: dati_base.correlation_id,
  ricevuta_at: dati_base.ricevuta_at,
  chiusa_at: new Date().toISOString(),
  canale: dati_base.canale,
  mittente: dati_base.mittente,
  testo_originale: dati_base.testo_originale,
  interpretazione: dati_base.interpretazione,
  interpretazione_meta: dati_base.interpretazione_meta,
  decisione: dati_base.decisione,
  approvazione: dati_base.approvazione,
  esiti,
  totali,
  esito_complessivo
};

const risposta_sincrona = {
  correlation_id: audit_record.correlation_id,
  esito: esito_complessivo,
  totali,
  azioni: esiti.map(e => ({
    tipo: e.tipo,
    stato: e.stato,
    riferimento: e.riferimento,
    errore: e.errore
  })),
  approvazione: dati_base.approvazione,
  provider_llm: dati_base.interpretazione_meta?.provider_usato,
  messaggio: esito_complessivo === 'completata'
    ? 'Tutte le azioni richieste sono state completate con successo.'
    : esito_complessivo === 'parziale'
      ? 'Alcune azioni sono fallite. Verificare il dettaglio nei log.'
      : 'Nessuna azione è stata eseguita (richiesta rifiutata o vuota).'
};

return [{ json: { audit_record, risposta_sincrona } }];

// Persisti Audit Log  (simulazione interna)
//
// Simula la scrittura del record di audit su un archivio append-only.
//
// PASSAGGIO A PRODUZIONE: sostituire con HTTP Request verso l'endpoint reale
// (Postgres tabella append-only, Elasticsearch index immutabile, S3 bucket con
// object lock, o data warehouse dedicato). La retention raccomandata e 24 mesi
// in linea con i requisiti tipici di compliance.

const dati = $input.first().json;
const audit_id = 'AUD-' +
  Date.now().toString(36).toUpperCase().slice(-6) + '-' +
  Math.random().toString(36).slice(2, 6).toUpperCase();

return [{
  json: {
    ...dati,
    audit_persistence: {
      audit_id,
      stato: 'persistito_mock',
      archiviato_at: new Date().toISOString()
    }
  }
}];
